\\\"description\\\": \\\"Config validation tests pass\\\",\\n    56│                     \\\"payload\\\": \\\"pytest tests/test_config.py -v\\\"\\n    57│                 },\\n    58│                 {\\n    59│                     \\\"type\\\": \\\"assertion\\\",\\n    60│                     \\\"description\\\": \\\"No hardcoded paths remain in bridge_cli.py or pipeline.py\\\",\\n    61│                     \\\"payload\\\": \\\"grep -r 'C:/tmp' src/bridge_cli.py src/pipeline.py || echo 'No hardcoded paths'\\\"\\n    62│                 }\\n    63│             ]\\n    64│         },\\n    65│         {\\n    66│             \\\"id\\\": \\\"F003\\\",\\n    67│             \\\"title\\\": \\\"Enhance DB schema v2 and add migration\\\",\\n    68│             \\\"description\\\": \\\"Add wave, dependencies, acceptance_criteria, token_cost columns to features table. Create github_sync table. Provide v1-to-v2 migration script.\\\",\\n    69│             \\\"status\\\": \\\"pending\\\",\\n    70│             \\\"owner_agent\\\": \\\"claude\\\",\\n    71│             \\\"estimated_complexity\\\": \\\"complex\\\",\\n    72│             \\\"dependencies\\\": [\\\"F001\\\", \\\"F002\\\"],\\n    73│             \\\"wave\\\": 2,\\n    74│             \\\"max_token_budget\\\": 50000,\\n    75│             \\\"acceptance_criteria\\\": [\\n    76│                 {\\n    77│                     \\\"type\\\": \\\"command\\\",\\n    78│                     \\\"description\\\": \\\"Migration script runs successfully on existing v1 database\\\",\\n    79│                     \\\"payload\\\": \\\"python src/migrate_v1_to_v2.py C:/tmp/multi-agent-pipeline/pipeline_state.db\\\"\\n    80│                 },\\n    81│                 {\\n    82│                     \\\"type\\\": \\\"test\\\",\\n    83│                     \\\"description\\\": \\\"DB schema tests verify all new columns exist\\\",\\n    84│                     \\\"payload\\\": \\\"pytest tests/test_state_store.py::test_schema_v2 -v\\\"\\n    85│                 },\\n    86│                 {\\n    87│                     \\\"type\\\": \\\"assertion\\\",\\n    88│                     \\\"description\\\": \\\"features.json can be imported into DB and exported back identically\\\",\\n    89│                     \\\"payload\\\": \\\"python -c 'from state_store import StateStore; s = StateStore(); s.import_features(\\\\\\\"features.json\\\\\\\"); s.export_features(\\\\\\\"/tmp/features_export.json\\\\\\\")'\\\"\\n    90│                 }\\n    91│             ]\\n    92│         },\\n    93│         {\\n    94│             \\\"id\\\": \\\"F004\\\",\\n    95│             \\\"title\\\": \\\"Implement bidirectional GitHub sync\\\",\\n    96│             \\\"description\\\": \\\"Create github_sync.py to synchronize feature status between DB and GitHub Issues. Support issue creation, status updates, and PR linking.\\\",\\n    97│             \\\"status\\\": \\\"pending\\\",\\n    98│             \\\"owner_agent\\\": \\\"claude\\\",\\n    99│             \\\"estimated_complexity\\\": \\\"complex\\\",\\n   100│             \\\"dependencies\\\": [\\\"F003\\\"],\\n   101│             \\\"wave\\\": 2,\\n   102│             \\\"max_token_budget\\\": 50000,\\n   103│             \\\"acceptance_criteria\\\": [\\n   104│                 {\\n   105│                     \\\"type\\\": \\\"command\\\",\\n   106│                     \\\"description\\\": \\\"GitHub sync creates issues for all pending features\\\",\\n   107│                     \\\"payload\\\": \\\"python src/github_sync.py --create-issues --project multi-agent-pipeline\\\"\\n   108│                 },\\n   109│                 {\\n   110│                     \\\"type\\\": \\\"test\\\",\\n   111│                     \\\"description\\\": \\\"Bidirectional sync tests pass with mock GitHub API\\\",\\n   112│                     \\\"payload\\\": \\\"pytest tests/test_github_sync.py -v\\\"\\n   113│                 },\\n   114│                 {\\n   115│                     \\\"type\\\": \\\"assertion\\\",\\n   116│                     \\\"description\\\": \\\"DB github_sync table records all sync operations\\\",\\n   117│                     \\\"payload\\\": \\\"python -c 'import sqlite3; c = sqlite3.connect(\\\\\\\"pipeline_state.db\\\\\\\"); print(c.execute(\\\\\\\"SELECT COUNT(*) FROM github_sync\\\\\\\").fetchone()[0])'\\\"\\n   118│                 }\\n   119│             ]\\n   120│         },\\n   121│         {\\n   122│             \\\"id\\\": \\\"F005\\\",\\n   123│             \\\"title\\\": \\\"Refactor agent communication with fallback channels\\\",\\n   124│             \\\"description\\\": \\\"Update adapters.py to support FileBasedChannel and MCPChannel as fallbacks when delegate_task times out. Implement channel selection strategy.\\\",\\n   125│             \\\"status\\\": \\\"pending\\\",\\n   126│             \\\"owner_agent\\\": \\\"claude\\\",\\n   127│             \\\"estimated_complexity\\\": \\\"complex\\\",\\n   128│             \\\"dependencies\\\": [\\\"F001\\\", \\\"F002\\\"],\\n   129│             \\\"wave\\\": 3,\\n   130│             \\\"max_token_budget\\\": 60000,\\n   131│             \\\"acceptance_criteria\\\": [\\n   132│                 {\\n   133│                     \\\"type\\\": \\\"command\\\",\\n   134│                     \\\"description\\\": \\\"File-based channel dispatches task and collects result\\\",\\n   135│                     \\\"payload\\\": \\\"python -c 'from adapters import FileBasedChannel; ch = FileBasedChannel(); ch.dispatch(\\\\\\\"claude\\\\\\\", {\\\\\\\"id\\\\\\\":\\\\\\\"test\\\\\\\"}); print(ch.collect(\\\\\\\"test\\\\\\\", timeout=5))'\\\"\\n   136│                 },\\n   137│                 {\\n   138│                     \\\"type\\\": \\\"test\\\",\\n   139│                     \\\"description\\\": \\\"Channel fallback tests verify delegate_task timeout triggers file-based fallback\\\",\\n   140│                     \\\"payload\\\": \\\"pytest tests/test_adapters.py::test_channel_fallback -v\\\"\\n   141│                 },\\n   142│                 {\\n   143│                     \\\"type\\\": \\\"assertion\\\",\\n   144│                     \\\"description\\\": \\\"AgentDispatcher tries all channels before failing\\\",\\n   145│                     \\\"payload\\\": \\\"python -c 'from adapters import AgentDispatcher; d = AgentDispatcher(); print(d.channels)'\\\"\\n   146│                 }\\n   147│             ]\\n   148│         },\\n   149│         {\\n   150│             \\\"id\\\": \\\"F006\\\",\\n   151│             \\\"title\\\": \\\"Integrate flexible approval system\\\",\\n   152│             \\\"description\\\": \\\"Refactor approval.py to support both GranularApproval (L1/L2/L3) and BlanketApproval modes. Integrate into pipeline.py phase transitions.\\\",\\n   153│             \\\"status\\\": \\\"pending\\\",\\n   154│             \\\"owner_agent\\\": \\\"claude\\\",\\n   155│             \\\"estimated_complexity\\\": \\\"medium\\\",\\n   156│             \\\"dependencies\\\": [\\\"F001\\\"],\\n   157│             \\\"wave\\\": 3,\\n   158│             \\\"max_token_budget\\\": 40000,\\n   159│             \\\"acceptance_criteria\\\": [\\n   160│                 {\\n   161│                     \\\"type\\\": \\\"command\\\",\\n   162│                     \\\"description\\\": \\\"Blanket approval mode allows auto-advance without human intervention\\\",\\n   163│                     \\\"payload\\\": \\\"python -c 'from approval import BlanketApproval; a = BlanketApproval(\\\\\\\"user\\\\\\\", {\\\\\\\"phases\\\\\\\":[\\\\\\\"design\\\\\\\",\\\\\\\"accept\\\\\\\"]}); print(a.is_authorized(\\\\\\\"design\\\\\\\", \\\\\\\"F001\\\\\\\"))'\\\"\\n   164│                 },\\n   165│                 {\\n   166│                     \\\"type\\\": \\\"test\\\",\\n   167│                     \\\"description\\\": \\\"Approval mode tests pass for both granular and blanket\\\",\\n   168│                     \\\"payload\\\": \\\"pytest tests/test_approval.py -v\\\"\\n   169│                 },\\n   170│                 {\\n   171│                     \\\"type\\\": \\\"assertion\\\",\\n   172│                     \\\"description\\\": \\\"Pipeline respects approval mode configuration\\\",\\n   173│                     \\\"payload\\\": \\\"python -c 'from pipeline import Pipeline; p = Pipeline(approval_mode=\\\\\\\"blanket\\\\\\\"); print(p.approval.__class__.__name__)'\\\"\\n   174│                 }\\n   175│             ]\\n   176│         },\\n   177│         {\\n   178│             \\\"id\\\": \\\"F007\\\",\\n   179│             \\\"title\\\": \\\"Unify exception hierarchy\\\",\\n   180│             \\\"description\\\": \\\"Replace mixed exception handling with unified PipelineException hierarchy. Update all modules to use consistent error types.\\\",\\n   181│             \\\"status\\\": \\\"pending\\\",\\n   182│             \\\"owner_agent\\\": \\\"claude\\\",\\n   183│             \\\"estimated_complexity\\\": \\\"medium\\\",\\n   184│             \\\"dependencies\\\": [\\\"F001\\\"],\\n   185│             \\\"wave\\\": 3,\\n   186│             \\\"max_token_budget\\\": 30000,\\n   187│             \\\"acceptance_criteria\\\": [\\n   188│                 {\\n   189│                     \\\"type\\\": \\\"command\\\",\\n   190│                     \\\"description\\\": \\\"All custom exceptions inherit from PipelineException\\\",\\n   191│                     \\\"payload\\\": \\\"python -c 'from models import PipelineException, ConstraintViolation, PhaseCheckFailed; print(issubclass(ConstraintViolation, PipelineException))'\\\"\\n   192│                 },\\n   193│                 {\\n   194│                     \\\"type\\\": \\\"test\\\",\\n   195│                     \\\"description\\\": \\\"Exception hierarchy tests pass\\\",\\n   196│                     \\\"payload\\\": \\\"pytest tests/test_exceptions.py -v\\\"\\n   197│                 },\\n   198│                 {\\n   199│                     \\\"type\\\": \\\"assertion\\\",\\n   200│                     \\\"description\\\": \\\"No bare except: or generic Exception catching in core modules\\\",\\n\\n[TRUNCATED] Showing lines 1-200 of 346. To continue, call read_file with path=\\\"C:\\\\tmp\\\\multi-agent-pipeline\\\\features_v2.json\\\" start_line=201 max_lines=200\\n</file>\"",
