est_create_with_structured(self) -> None:\\n    53│         r = AgentResult(success=True, output=\\\"ok\\\", exit_code=0, structured={\\\"key\\\": \\\"val\\\"})\\n    54│         assert r.structured == {\\\"key\\\": \\\"val\\\"}\\n    55│ \\n    56│     def test_defaults(self) -> None:\\n    57│         r = AgentResult(success=True, output=\\\"\\\")\\n    58│         assert r.tokens_used == 0\\n    59│         assert r.cost_usd == 0.0\\n    60│         assert r.latency_ms == 0\\n    61│         assert r.exit_code == 0\\n    62│ \\n    63│     def test_to_dict(self) -> None:\\n    64│         r = AgentResult(success=True, output=\\\"o\\\", exit_code=0, structured={\\\"a\\\": 1})\\n    65│         d = r.to_dict()\\n    66│         assert d[\\\"success\\\"] is True\\n    67│         assert d[\\\"output\\\"] == \\\"o\\\"\\n    68│         assert d[\\\"structured\\\"] == {\\\"a\\\": 1}\\n    69│ \\n    70│     def test_from_dict(self) -> None:\\n    71│         d = {\\n    72│             \\\"success\\\": False,\\n    73│             \\\"output\\\": \\\"fail\\\",\\n    74│             \\\"structured\\\": None,\\n    75│             \\\"tokens_used\\\": 10,\\n    76│             \\\"cost_usd\\\": 0.01,\\n    77│             \\\"latency_ms\\\": 100,\\n    78│             \\\"exit_code\\\": 1,\\n    79│             \\\"error_message\\\": \\\"bad\\\",\\n    80│         }\\n    81│         r = AgentResult.from_dict(d)\\n    82│         assert r.success is False\\n    83│         assert r.tokens_used == 10\\n    84│         assert r.cost_usd == 0.01\\n    85│ \\n    86│ \\n    87│ # ───────────────────────────────────────────────────────────────\\n    88│ # OutputParser 测试（解析层）\\n    89│ # ───────────────────────────────────────────────────────────────\\n    90│ \\n    91│ class TestOutputParser:\\n    92│     def test_parse_json_block_valid(self) -> None:\\n    93│         text = 'some text\\\\n```json\\\\n{\\\"a\\\": 1}\\\\n```\\\\nmore text'\\n    94│         result = OutputParser.parse_json_block(text)\\n    95│         assert result == {\\\"a\\\": 1}\\n    96│ \\n    97│     def test_parse_json_block_no_markers(self) -> None:\\n    98│         text = '{\\\"b\\\": 2}'\\n    99│         result = OutputParser.parse_json_block(text)\\n   100│         assert result == {\\\"b\\\": 2}\\n   101│ \\n   102│     def test_parse_json_block_invalid_json(self) -> None:\\n   103│         with pytest.raises(ParseError):\\n   104│             OutputParser.parse_json_block(\\\"not json\\\")\\n   105│ \\n   106│     def test_parse_json_block_empty(self) -> None:\\n   107│         with pytest.raises(ParseError):\\n   108│             OutputParser.parse_json_block(\\\"\\\")\\n   109│ \\n   110│     def test_extract_code_blocks(self) -> None:\\n   111│         text = \\\"```python\\\\nprint(1)\\\\n```\\\\n```bash\\\\necho hi\\\\n```\\\"\\n   112│         blocks = OutputParser.extract_code_blocks(text)\\n   113│         assert len(blocks) == 2\\n   114│         assert blocks[0] == (\\\"python\\\", \\\"print(1)\\\")\\n   115│         assert blocks[1] == (\\\"bash\\\", \\\"echo hi\\\")\\n   116│ \\n   117│     def test_extract_code_blocks_no_lang(self) -> None:\\n   118│         text = \\\"```\\\\ncode\\\\n```\\\"\\n   119│         blocks = OutputParser.extract_code_blocks(text)\\n   120│         assert blocks[0] == (None, \\\"code\\\")\\n   121│ \\n   122│     def test_extract_code_blocks_empty(self) -> None:\\n   123│         assert OutputParser.extract_code_blocks(\\\"no code\\\") == []\\n   124│ \\n   125│     def test_heuristic_extract_p0_issues(self) -> None:\\n   126│         text = \\\"\\\"\\\"\\n   127│ ## 审查报告\\n   128│ \\n   129│ **P0** 文件 app.py 第 42 行: 空指针风险\\n   130│ **P0** 文件 utils.py 第 10 行: 除以零\\n   131│ \\\"\\\"\\\"\\n   132│         issues = OutputParser.heuristic_extract_issues(text)\\n   133│         assert len(issues) == 2\\n   134│         assert issues[0][\\\"level\\\"] == \\\"P0\\\"\\n   135│         assert issues[0][\\\"file\\\"] == \\\"app.py\\\"\\n   136│         assert issues[0][\\\"line\\\"] == 42\\n   137│ \\n   138│     def test_heuristic_extract_p1_p2(self) -> None:\\n   139│         text = \\\"**P1** 文件 main.py 第 5 行: 性能问题\\\\n**P2** 文件 main.py 第 8 行: 命名不佳\\\"\\n   140│         issues = OutputParser.heuristic_extract_issues(text)\\n   141│         assert len(issues) == 2\\n   142│         assert issues[0][\\\"level\\\"] == \\\"P1\\\"\\n   143│         assert issues[1][\\\"level\\\"] == \\\"P2\\\"\\n   144│ \\n   145│     def test_heuristic_extract_no_issues(self) -> None:\\n   146│         assert OutputParser.heuristic_extract_issues(\\\"clean code\\\") == []\\n   147│ \\n   148│     def test_heuristic_extract_various_formats(self) -> None:\\n   149│         texts = [\\n   150│             \\\"P0: file.py line 10: bug\\\",\\n   151│             \\\"**P0** file.py line 10: bug\\\",\\n   152│             \\\"- P0 file.py:10 bug\\\",\\n   153│             \\\"P0 | file.py | 10 | bug\\\",\\n   154│         ]\\n   155│         for t in texts:\\n   156│             issues = OutputParser.heuristic_extract_issues(t)\\n   157│             assert len(issues) >= 1, f\\\"failed for {t!r}\\\"\\n   158│             assert issues[0][\\\"level\\\"] == \\\"P0\\\"\\n   159│ \\n   160│     def test_extract_diff_stats(self) -> None:\\n   161│         text = \\\" app.py | 3 +++\\\\n utils.py | 1 -\\\"\\n   162│         stats = OutputParser.extract_diff_stats(text)\\n   163│         assert stats == {\\\"app.py\\\": {\\\"add\\\": 3, \\\"del\\\": 0}, \\\"utils.py\\\": {\\\"add\\\": 0, \\\"del\\\": 1}}\\n   164│ \\n   165│     def test_extract_diff_stats_empty(self) -> None:\\n   166│         assert OutputParser.extract_diff_stats(\\\"\\\") == {}\\n   167│ \\n   168│     def test_extract_git_commit_hash(self) -> None:\\n   169│         text = \\\"[main abc1234] commit message\\\"\\n   170│         assert OutputParser.extract_git_commit_hash(text) == \\\"abc1234\\\"\\n   171│ \\n   172│     def test_extract_gi