      "line": "                \"content\": \"<file path=\\\"C:\\\\tmp\\\\multi-agent-pipeline\\\\src\\\\budget_guard.py\\\" total_lines=\\\"620\\\" shown_lines=\\\"1-200\\\" truncated=\\\"true\\\" next_start_line=\\\"201\\\">\\n     1│ \\\"\\\"\\\"src/budget_guard.py — 3-Level Budget Enforcement Guard (Q05)\\n     2│ \\n     3│ Implements:\\n     4│ - 3-level budget enforcement: warning (80%), soft_cap (100%), hard_cap (150%)\\n     5│ - Per-feature token limit tracking\\n     6│ - Per-project USD cost limit tracking\\n     7│ - Pre-flight budget checks before any agent call\\n     8│ - Integration with existing TokenBudget from task_decomposer\\n     9│ \\n    10│ Design:\\n    11│   BudgetGuard is the central gatekeeper. Before any agent operation, it checks:\\n    12│     1. Per-feature token budget (via TokenBudget with feature-level limits)\\n    13│     2. Per-project USD budget (cumulative cost across all features)\\n    14│   At 80% → WARNING (log + notify, operation proceeds)\\n    15│   At 100% → SOFT_CAP (pause new tasks, require user confirmation)\\n    16│   At 150% → HARD_CAP (force-stop, reject all new operations)\\n    17│ \\\"\\\"\\\"\\n    18│ \\n    19│ from __future__ import annotations\\n    20│ \\n    21│ import logging\\n    22│ import time\\n    23│ from dataclasses import dataclass, field\\n    24│ from enum import Enum\\n    25│ from typing import Any, Callable, Dict, List, Optional, Tuple, TypeVar\\n    26│ \\n    27│ try:\\n    28│     from task_decomposer import TokenBudget\\n    29│ except ImportError:\\n    30│     from src.task_decomposer import TokenBudget\\n    31│ \\n    32│ T = TypeVar(\\\"T\\\")\\n    33│ \\n    34│ logger = logging.getLogger(__name__)\\n    35│ \\n    36│ \\n    37│ # ───────────────────────────────────────────────────────────────\\n    38│ # Budget Level Enum\\n    39│ # ───────────────────────────────────────────────────────────────\\n    40│ \\n    41│ class BudgetLevel(Enum):\\n    42│     \\\"\\\"\\\"Budget enforcement level after a charge or check.\\\"\\\"\\\"\\n    43│     OK = \\\"ok\\\"               # Under 80% — normal operation\\n    44│     WARNING = \\\"warning\\\"     # ≥ 80% — notify, but proceed\\n    45│     SOFT_CAP = \\\"soft_cap\\\"   # ≥ 100% — pause new, require confirmation\\n    46│     HARD_CAP = \\\"hard_cap\\\"   # ≥ 150% — force-stop, reject all\\n    47│     UNLIMITED = \\\"unlimited\\\" # No limit set\\n    48│ \\n    49│ \\n    50│ # ───────────────────────────────────────────────────────────────\\n    51│ # Budget Guard Exception\\n    52│ # ───────────────────────────────────────────────────────────────\\n    53│ \\n    54│ class BudgetExceededError(Exception):\\n    55│     \\\"\\\"\\\"Raised when an operation is blocked by budget enforcement.\\\"\\\"\\\"\\n    56│     def __init__(\\n    57│         self,\\n    58│         level: BudgetLevel,\\n    59│         message: str,\\n    60│         feature_id: Optional[str] = None,\\n    61│         project_id: Optional[str] = None,\\n    62│     ):\\n    63│         self.level = level\\n    64│         self.feature_id = feature_id\\n    65│         self.project_id = project_id\\n    66│         super().__init__(message)\\n    67│ \\n    68│ \\n    69│ class BudgetWarning(Exception):\\n    70│     \\\"\\\"\\\"Non-fatal warning: operation proceeds but budget threshold crossed.\\\"\\\"\\\"\\n    71│     def __init__(\\n    72│         self,\\n    73│         level: BudgetLevel,\\n    74│         message: str,\\n    75│         feature_id: Optional[str] = None,\\n    76│         project_id: Optional[str] = None,\\n    77│     ):\\n    78│         self.level = level\\n    79│         self.feature_id = feature_id\\n    80│         self.project_id = project_id\\n    81│         super().__init__(message)\\n    82│ \\n    83│ \\n    84│ # ───────────────────────────────────────────────────────────────\\n    85│ # USD Budget Tracker\\n    86│ # ───────────────────────────────────────────────────────────────\\n    87│ \\n    88│ @dataclass\\n    89│ class USDBudget:\\n    90│     \\\"\\\"\\\"Per-project USD cost budget tracker.\\n    91│ \\n    92│     Attributes:\\n    93│         limit_usd: Maximum USD allowed for the project (0 = unlimited).\\n    94│         spent_usd: Cumulative USD spent so far.\\n    95│     \\\"\\\"\\\"\\n    96│ \\n    97│     limit_usd: float = 0.0\\n    98│     spent_usd: float = 0.0\\n    99│ \\n   100│     WARNING_RATIO: float = field(default=0.8, repr=False)\\n   101│     SOFT_CAP_RATIO: float = field(default=1.0, repr=False)\\n   102│     HARD_CAP_RATIO: float = field(default=1.5, repr=False)\\n   103│ \\n   104│     @property\\n   105│     def remaining(self) -> float:\\n   106│         \\\"\\\"\\\"Remaining USD before hitting the soft cap.\\\"\\\"\\\"\\n   107│         if self.limit_usd <= 0:\\n   108│             return -1.0  # unlimited\\n   109│         return max(0.0, self.limit_usd - self.spent_usd)\\n   110│ \\n   111│     @property\\n   112│     def usage_ratio(self) -> float:\\n   113│         \\\"\\\"\\\"Ratio of spent / limit (0.0-∞).\\\"\\\"\\\"\\n   114│         if self.limit_usd <= 0:\\n   115│             return 0.0\\n   116│         return self.spent_usd / self.limit_usd\\n   117│ \\n   118│     def check(self) -> BudgetLevel:\\n   119│         \\\"\\\"\\\"Check current USD budget status.\\\"\\\"\\\"\\n   120│         if self.limit_usd <= 0:\\n   121│             return BudgetLevel.UNLIMITED\\n   122│         ratio = self.usage_ratio\\n   123│         if ratio >= self.HARD_CAP_RATIO:\\n   124│             return BudgetLevel.HARD_CAP\\n   125│         if ratio >= self.SOFT_CAP_RATIO:\\n   126│             return BudgetLevel.SOFT_CAP\\n   127│         if ratio >= self.WARNING_RATIO:\\n   128│             return BudgetLevel.WARNING\\n   129│         return BudgetLevel.OK\\n   130│ \\n   131│     def can_allocate(self, cost_usd: float) -> bool:\\n   132│         \\\"\\\"\\\"Check whether cost_usd can be added without exceeding HARD_CAP.\\\"\\\"\\\"\\n   133│         if self.limit_usd <= 0:\\n   134│             return True\\n   135│         return (self.spent_usd + cost_usd) <= (self.limit_usd * self.HARD_CAP_RATIO)\\n   136│ \\n   137│     def charge(self, cost_usd: float) -> BudgetLevel:\\n   138│         \\\"\\\"\\\"Charge cost_usd to the budget. Returns new level.\\\"\\\"\\\"\\n   139│         self.spent_usd += cost_usd\\n   140│         return self.check()\\n   141│ \\n   142│     def to_dict(self) -> Dict[str, Any]:\\n   143│         return {\\n   144│             \\\"limit_usd\\\": self.limit_usd,\\n   145│             \\\"spent_usd\\\": round(self.spent_usd, 4),\\n   146│             \\\"remaining\\\": round(self.remaining, 4) if self.remaining >= 0 else -1,\\n   147│             \\\"usage_ratio\\\": round(self.usage_ratio, 4),\\n   148│             \\\"status\\\": self.check().value,\\n   149│         }\\n   150│ \\n   151│ \\n   152│ # ───────────────────────────────────────────────────────────────\\n   153│ # Feature Budget Record\\n   154│ # ───────────────────────────────────────────────────────────────\\n   155│ \\n   156│ @dataclass\\n   157│ class FeatureBudget:\\n   158│     \\\"\\\"\\\"Per-feature budget tracking combining token + USD dimensions.\\n   159│ \\n   160│     Attributes:\\n   161│         feature_id: Unique feature identifier.\\n   162│         token_budget: TokenBudget instance for this feature.\\n   163│         token_spent: Total tokens consumed by this feature.\\n   164│         cost_usd: Total USD cost for this feature.\\n   165│     \\\"\\\"\\\"\\n   166│ \\n   167│     feature_id: str\\n   168│     token_budget: TokenBudget = field(default_factory=TokenBudget)\\n   169│     token_spent: int = 0\\n   170│     cost_usd: float = 0.0\\n   171│ \\n   172│     def charge_tokens(self, tokens: int, cost_usd: float = 0.0) -> BudgetLevel:\\n   173│         \\\"\\\"\\\"Charge tokens and optional USD cost to this feature.\\\"\\\"\\\"\\n   174│         self.token_spent += tokens\\n   175│         self.token_budget.spent = self.token_spent\\n   176│         if cost_usd:\\n   177│             self.cost_usd += cost_usd\\n   178│         return BudgetLevel(self.token_budget.check())\\n   179│ \\n   180│     def to_dict(self) -> Dict[str, Any]:\\n   181│         return {\\n   182│             \\\"feature_id\\\": self.feature_id,\\n   183│             \\\"token_limit\\\": self.token_budget.limit,\\n   184│             \\\"token_spent\\\": self.token_spent,\\n   185│             \\\"token_remaining\\\": self.token_budget.remaining,\\n   186│             \\\"cost_usd\\\": round(self.cost_usd, 4),\\n   187│             \\\"status\\\": self.token_budget.check(),\\n   188│         }\\n   189│ \\n   190│ \\n   191│ # ───────────────────────────────────────────────────────────────\\n   192│ # Budget Guard — Central Gatekeeper\\n   193│ # ───────────────────────────────────────────────────────────────\\n   194│ \\n   195│ @dataclass\\n   196│ class BudgetGuard:\\n   197│     \\\"\\\"\\\"Central budget enforcement guard.\\n   198│ \\n   199│     Tracks per-feature token budgets and a per-project USD budget.\\n   200│     Before any agent call, checks both dimensions and raises\\n\\n[TRUNCATED] Showing lines 1-200 of 620. To continue, call read_file with path=\\\"C:\\\\tmp\\\\multi-agent-pipeline\\\\src\\\\budget_guard.py\\\" start_line=201 max_lines=200\\n</file>\"",
