    40│ \\n    41│ \\n    42│ # ───────────────────────────────────────────────────────────────\\n    43│ # GateResult dataclass\\n    44│ # ───────────────────────────────────────────────────────────────\\n    45│ \\n    46│ @dataclass\\n    47│ class GateResult:\\n    48│     \\\"\\\"\\\"Unified result from a gate run.\\n    49│ \\n    50│     Attributes:\\n    51│         passed: True if all checks in this gate passed.\\n    52│         level: The GateLevel this result belongs to.\\n    53│         checks_run: Total number of checks executed.\\n    54│         checks_passed: Number of checks that passed.\\n    55│         failures: List of (check_name, reason) tuples for failed checks.\\n    56│         duration_ms: Wall-clock duration of the gate run in milliseconds.\\n    57│     \\\"\\\"\\\"\\n    58│     passed: bool\\n    59│     level: GateLevel\\n    60│     checks_run: int\\n    61│     checks_passed: int\\n    62│     failures: List[Tuple[str, str]] = field(default_factory=list)\\n    63│     duration_ms: float = 0.0\\n    64│ \\n    65│ \\n    66│ # ───────────────────────────────────────────────────────────────\\n    67│ # Check type alias\\n    68│ # ───────────────────────────────────────────────────────────────\\n    69│ \\n    70│ CheckFunc = Callable[..., Tuple[bool, str]]\\n    71│ \\n    72│ \\n    73│ # ───────────────────────────────────────────────────────────────\\n    74│ # Core: run_checks\\n    75│ # ───────────────────────────────────────────────────────────────\\n    76│ \\n    77│ def run_checks(\\n    78│     checks: List[Tuple[str, CheckFunc, tuple]],\\n    79│     level: GateLevel,\\n    80│     timeout: float,\\n    81│ ) -> GateResult:\\n    82│     \\\"\\\"\\\"Run a list of checks and aggregate results into a GateResult.\\n    83│ \\n    84│     Parameters:\\n    85│         checks: List of (name, callable, args) tuples.\\n    86│         level: The GateLevel for reporting / context.\\n    87│         timeout: Total timeout in seconds (soft — best-effort).\\n    88│ \\n    89│     Returns:\\n    90│         GateResult with aggregated pass/fail data.\\n    91│     \\\"\\\"\\\"\\n    92│     start = time.perf_counter()\\n    93│     failures: List[Tuple[str, str]] = []\\n    94│     checks_run = 0\\n    95│     checks_passed = 0\\n    96│ \\n    97│     deadline = start + timeout\\n    98│ \\n    99│     for name, func, args in checks:\\n   100│         if time.perf_counter() > deadline:\\n   101│             failures.append((name, \\\"Gate timeout exceeded\\\"))\\n   102│             checks_run += 1\\n   103│             continue\\n   104│ \\n   105│         try:\\n   106│             passed, reason = func(*args)\\n   107│             checks_run += 1\\n   108│             if passed:\\n   109│                 checks_passed += 1\\n   110│             else:\\n   111│                 failures.append((name, reason))\\n   112│         except Exception as exc:\\n   113│             checks_run += 1\\n   114│             failures.append((name, f\\\"Check raised exception: {exc}\\\"))\\n   115│ \\n   116│     elapsed = (time.perf_counter() - start) * 1000.0\\n   117│     all_passed = len(failures) == 0 and checks_run > 0\\n   118│ \\n   119│     return GateResult(\\n   120│         passed=all_passed,\\n   121│         level=level,\\n   122│         checks_run=checks_run,\\n   123│         checks_passed=checks_passed,\\n   124│         failures=failures,\\n   125│         duration_ms=elapsed,\\n   126│     )\\n   127│ \\n   128│ \\n   129│ # ═══════════════════════════════════════════════════════════════\\n   130│ # Level 0 checks — POST_GEN (<5s)\\n   131│ # ═══════════════════════════════════════════════════════════════\\n   132│ \\n   133│ def _check_ai_origin_mark(file_path: Path) -> Tuple[bool, str]:\\n   134│     \\\"\\\"\\\"Check that the file contains an AI-origin marker comment.\\n   135│ \\n   136│     Looks for markers like '# AI-generated', '// AI-generated',\\n   137│     'Generated by AI'