]\\n    43│         features = snapshot[\\\"features\\\"]\\n    44│ \\\"\\\"\\\"\\n    45│ \\n    46│ from __future__ import annotations\\n    47│ \\n    48│ import json\\n    49│ import logging\\n    50│ import threading\\n    51│ import time\\n    52│ from dataclasses import dataclass, field\\n    53│ from datetime import datetime, timezone\\n    54│ from pathlib import Path\\n    55│ from typing import Any, Callable, Dict, List, Optional, Tuple, Union\\n    56│ \\n    57│ logger = logging.getLogger(__name__)\\n    58│ \\n    59│ # ───────────────────────────────────────────────────────────────\\n    60│ # Dual-import pattern (package / flat)\\n    61│ # ───────────────────────────────────────────────────────────────\\n    62│ \\n    63│ try:\\n    64│     from state_store import StateStore\\n    65│ except ImportError:\\n    66│     from src.state_store import StateStore\\n    67│ \\n    68│ try:\\n    69│     from checkpointer import Checkpointer\\n    70│ except ImportError:\\n    71│     from src.checkpointer import Checkpointer\\n    72│ \\n    73│ try:\\n    74│     from models import (\\n    75│         PipelineError,\\n    76│         Phase,\\n    77│     )\\n    78│ except ImportError:\\n    79│     from src.models import (\\n    80│         PipelineError,\\n    81│         Phase,\\n    82│     )\\n    83│ \\n    84│ \\n    85│ # ───────────────────────────────────────────────────────────────\\n    86│ # Data model\\n    87│ # ───────────────────────────────────────────────────────────────\\n    88│ \\n    89│ @dataclass\\n    90│ class WatchdogSnapshot:\\n    91│     \\\"\\\"\\\"A single global state snapshot captured by the watchdog.\\n    92│ \\n    93│     Fields:\\n    94│         id: Auto-incremented snapshot ID (None before persisting).\\n    95│         project_id: The project identifier.\\n    96│         phase: Current pipeline phase name (e.g. 'develop', 'test').\\n    97│         features_json: JSON-encoded list of feature status dicts.\\n    98│         agents_json: JSON-encoded agent state information.\\n    99│         workers_json: JSON-encoded worker pool state.\\n   100│         circuit_state: Current circuit breaker state (e.g. 'CLOSED').\\n   101│         budget_remaining: Remaining budget (token cost or USD).\\n   102│         metadata_json: JSON-encoded arbitrary metadata dictionary.\\n   103│         health: Health marker — 'healthy', 'degraded', or 'fatal'.\\n   104│         created_at: ISO-8601 UTC timestamp.\\n   105│     \\\"\\\"\\\"\\n   106│ \\n   107│     id: Optional[int] = None\\n   108│     project_id: str = \\\"\\\"\\n   109│     phase: str = \\\"\\\"\\n   110│     features_json: str = \\\"[]\\\"\\n   111│     agents_json: str = \\\"{}\\\"\\n   112│     workers_json: str = \\\"{}\\\"\\n   113│     circuit_state: str = \\\"\\\"\\n   114│     budget_remaining: float = 0.0\\n   115│     metadata_json: str = \\\"{}\\\"\\n   116│     health: str = \\\"healthy\\\"\\n   117│     created_at: Optional[str] = None\\n   118│ \\n   119│     def features_list(self) -> List[Dict[str, Any]]:\\n   120│         \\\"\\\"\\\"Decode features_json into a list of feature dicts.\\\"\\\"\\\"\\n   121│         return json.loads(self.features_json) if self.features_json else []\\n   122│ \\n   123│     def agents_dict(self) -> Dict[str, Any]:\\n   124│         \\\"\\\"\\\"Decode agents_json into a dict.\\\"\\\"\\\"\\n   125│         return json.loads(self.agents_json) if self.agents_json else {}\\n   126│ \\n   127│     def workers_dict(self) -> Dict[str, Any]:\\n   128│         \\\"\\\"\\\"Decode workers_json into a dict.\\\"\\\"\\\"\\n   129│         return json.loads(self.workers_json) if self.workers_json else {}\\n   130│ \\n   131│     def metadata_dict(self) -> Dict[str, Any]:\\n   132│         \\\"\\\"\\\"Decode metadata_json into a dict.\\\"\\\"\\\"\\n   133│         return json.loads(self.metadata_json) if self.metadata_json else {}\\n   134│ \\n   135│     def is_healthy(self) -> bool:\\n   136│         \\\"\\\"\\\"Return True if this snapshot represents a healthy pipeline state.\\\"\\\"\\\"\\n   137│         return self.health == \\\"healthy\\\"\\n   138│ \\n   139│ \\n   140│ # ───────────────────────────────────────────────────────────────\\n   141│ # State provider protocol\\n   142│ # ───────────────────────────────────────────────────────────────\\n   143│ \\n   144│ # A state provider is a callable that returns a dict with state info.\\n   145│ # Registered providers are called during each snapshot cycle.\\n   146│ StateProvider = Callable[[], Dict[str, Any]]\\n   147│ \\n   148│ \\n   149│ # ───────────────────────────────────────────────────────────────\\n   150│ # Watchdog — Periodic global state snapshot saver\\n   151│ # ───────────────────────────────────────────────────────────────\\n   152│ \\n   153│ class Watchdog:\\n   154│     \\\"\\\"\\\"Periodic global state snapshot saver with crash recovery.\\n   155│ \\n   156│     Runs a background thread that captures the full pipeline state at\\n   157│     configurable intervals and persists it via the Checkpointer's\\n   158│     StateStore.  On crash / restart, the latest snapshot can be\\n   159│     recovered to resume from where the pipeline left off.\\n   160│ \\n   161│     Features:\\n   162│         - Configurable snapshot interval (default 30 seconds).\\n   163│         - Crash recovery: ``recover_latest(project_id)`` returns the\\n   164│           latest healthy snapshot, or the most recent snapshot of any\\n   165│           health level.\\n   166│         - Pluggable state providers: other modules can register\\n   167│           callables that contribute state to each snapshot.\\n   168│         - Thread-safe: snapshot writes are protected by a lock.\\n   169│         - Graceful start/stop via ``start()`` / ``stop()``.\\n   170│         - Snapshot pruning: old snapshots beyond ``max_snapshots``\\n   171│           (default 100) are automatically removed.\\n   172│ \\n   173│     Dependencies:\\n   174│         - ``StateStore``: provides the SQLite connection.\\n   175│         - ``Checkpointer``: used for subtask-level resume coordination.\\n   176│ \\n   177│     Usage::\\n   178│ \\n   179│         store = StateStore(Path(\\\"pipeline_state.db\\\"))\\n   180│         wd = Watchdog(store, interval=30.0)\\n   181│ \\n   182│         # Register providers\\n   183│         wd.register_provider(\\\"pipeline\\\", my_pipeline_state_fn)\\n   184│ \\n   185│         # Start background snapshots\\n   186│         wd.start()\\n   187│ \\n   188│         # ... run pipeline ...\\n   189│ \\n   190│         # On crash recovery:\\n   191│         snap = wd.recover_latest(\\\"my-project\\\")\\n   192│         if snap:\\n   193│             print(f\\\"Recovered phase: {snap['phase']}\\\")\\n   194│     \\\"\\\"\\\"\\n   195│ \\n   196│     # ── SQL for the watchdog_snapshots table ─────────────────────\\n   197│ \\n   198│     WATCHDOG_SNAPSHOTS_SQL: str = \\\"\\\"\\\"\\\\\\n   199│ CREATE TABLE IF NOT EXISTS watchdog_snapshots (\\n   200│     id INTEGER PRIMARY KEY AUTOINCREMENT,\\n\\n[TRUNCATED] Showing lines 1-200 of 977. To continue, call read_file with path=\\\"C:\\\\tmp\\\\multi-agent-pipeline\\\\src\\\\watchdog.py\\\" start_line=201 max_lines=200\\n</file>\"",
