      "line": "                \"content\": \"<file path=\\\"C:\\\\tmp\\\\multi-agent-pipeline\\\\src\\\\system_constraint.py\\\" total_lines=\\\"578\\\" shown_lines=\\\"1-200\\\" truncated=\\\"true\\\" next_start_line=\\\"201\\\">\\n     1│ \\\"\\\"\\\"src/system_constraint.py — 系统级约束层 (F024)\\n     2│ \\n     3│ 自动约束任务路由，不是 Hermes 自我约束：\\n     4│ - 编码任务 → Claude Code\\n     5│ - 审核任务 → CodeWhale\\n     6│ - 测试任务 → Qwen Code\\n     7│ - Hermes 仅限编排权限，禁止直接执行编码/审核/测试任务\\n     8│ \\n     9│ 验收标准：\\n    10│ 1. 约束层自动拦截违规操作\\n    11│ 2. 约束层单元测试通过\\n    12│ 3. Hermes 尝试编码被自动拦截\\n    13│ \\\"\\\"\\\"\\n    14│ \\n    15│ from __future__ import annotations\\n    16│ \\n    17│ from dataclasses import dataclass, field\\n    18│ from enum import Enum, auto\\n    19│ from typing import Any, Callable, Dict, List, Optional, Tuple, Type\\n    20│ \\n    21│ \\n    22│ # ───────────────────────────────────────────────────────────────\\n    23│ # 异常定义\\n    24│ # ───────────────────────────────────────────────────────────────\\n    25│ \\n    26│ class ConstraintViolation(Exception):\\n    27│     \\\"\\\"\\\"系统级约束违规异常\\n    28│ \\n    29│     当任务被路由到错误的 Agent，或 Hermes 尝试执行非编排操作时抛出。\\n    30│     \\\"\\\"\\\"\\n    31│ \\n    32│     def __init__(\\n    33│         self,\\n    34│         message: str,\\n    35│         *,\\n    36│         task_type: Optional[str] = None,\\n    37│         attempted_agent: Optional[str] = None,\\n    38│         required_agent: Optional[str] = None,\\n    39│         action: Optional[str] = None,\\n    40│     ) -> None:\\n    41│         super().__init__(message)\\n    42│         self.task_type = task_type\\n    43│         self.attempted_agent = attempted_agent\\n    44│         self.required_agent = required_agent\\n    45│         self.action = action\\n    46│ \\n    47│     def to_dict(self) -> Dict[str, Any]:\\n    48│         return {\\n    49│             \\\"message\\\": str(self),\\n    50│             \\\"task_type\\\": self.task_type,\\n    51│             \\\"attempted_agent\\\": self.attempted_agent,\\n    52│             \\\"required_agent\\\": self.required_agent,\\n    53│             \\\"action\\\": self.action,\\n    54│         }\\n    55│ \\n    56│ \\n    57│ class HermesPermissionDenied(ConstraintViolation):\\n    58│     \\\"\\\"\\\"Hermes 权限不足异常\\n    59│ \\n    60│     当 Hermes 尝试执行仅限其他 Agent 的操作时抛出。\\n    61│     \\\"\\\"\\\"\\n    62│     pass\\n    63│ \\n    64│ \\n    65│ # ───────────────────────────────────────────────────────────────\\n    66│ # 任务类型枚举\\n    67│ # ───────────────────────────────────────────────────────────────\\n    68│ \\n    69│ class TaskType(Enum):\\n    70│     \\\"\\\"\\\"系统支持的任务类型\\\"\\\"\\\"\\n    71│     CODE = \\\"code\\\"           # 编码/开发任务\\n    72│     REVIEW = \\\"review\\\"       # 代码审核任务\\n    73│     TEST = \\\"test\\\"           # 测试任务（单元测试/E2E）\\n    74│     DOC = \\\"doc\\\"             # 文档生成任务\\n    75│     E2E = \\\"e2e\\\"             # E2E 测试任务\\n    76│     ORCHESTRATE = \\\"orchestrate\\\"  # 编排/协调任务（仅限 Hermes）\\n    77│     DEPLOY = \\\"deploy\\\"       # 部署任务\\n    78│     ANALYZE = \\\"analyze\\\"   # 分析任务\\n    79│ \\n    80│ \\n    81│ # ───────────────────────────────────────────────────────────────\\n    82│ # Agent 标识枚举\\n    83│ # ───────────────────────────────────────────────────────────────\\n    84│ \\n    85│ class Agent(Enum):\\n    86│     \\\"\\\"\\\"系统中可用的 Agent\\\"\\\"\\\"\\n    87│     CLAUDE = \\\"claude\\\"       # Claude Code — 编码专家\\n    88│     CODEWHALE = \\\"codewhale\\\" # CodeWhale — 审核专家\\n    89│     QWEN = \\\"qwen\\\"           # Qwen Code — 测试专家\\n    90│     HERMES = \\\"hermes\\\"       # Hermes — 编排器（仅协调）\\n    91│ \\n    92│ \\n    93│ # ───────────────────────────────────────────────────────────────\\n    94│ # 任务类型到 Agent 的映射（系统级约束核心）\\n    95│ # ───────────────────────────────────────────────────────────────\\n    96│ \\n    97│ TASK_AGENT_MAP: Dict[TaskType, Agent] = {\\n    98│     TaskType.CODE: Agent.CLAUDE,\\n    99│     TaskType.REVIEW: Agent.CODEWHALE,\\n   100│     TaskType.TEST: Agent.QWEN,\\n   101│     TaskType.DOC: Agent.QWEN,\\n   102│     TaskType.E2E: Agent.QWEN,\\n   103│     TaskType.ORCHESTRATE: Agent.HERMES,\\n   104│     TaskType.DEPLOY: Agent.HERMES,\\n   105│     TaskType.ANALYZE: Agent.HERMES,\\n   106│ }\\n   107│ \\n   108│ # Agent 能力映射（反向查询）\\n   109│ AGENT_CAPABILITIES: Dict[Agent, List[TaskType]] = {\\n   110│     Agent.CLAUDE: [TaskType.CODE],\\n   111│     Agent.CODEWHALE: [TaskType.REVIEW],\\n   112│     Agent.QWEN: [TaskType.TEST, TaskType.DOC, TaskType.E2E],\\n   113│     Agent.HERMES: [TaskType.ORCHESTRATE, TaskType.DEPLOY, TaskType.ANALYZE],\\n   114│ }\\n   115│ \\n   116│ \\n   117│ # ───────────────────────────────────────────────────────────────\\n   118│ # 约束配置\\n   119│ # ───────────────────────────────────────────────────────────────\\n   120│ \\n   121│ @dataclass\\n   122│ class ConstraintConfig:\\n   123│     \\\"\\\"\\\"系统约束层配置\\\"\\\"\\\"\\n   124│     # 是否启用严格模式（违规时抛出异常而非返回错误）\\n   125│     strict_mode: bool = True\\n   126│     # 是否允许 Hermes 在紧急模式下执行受限任务\\n   127│     emergency_override: bool = False\\n   128│     # 紧急模式密码（简单哈希校验）\\n   129│     _emergency_password_hash: Optional[str] = None\\n   130│     # 违规回调（用于日志/告警）\\n   131│     violation_callbacks: List[Callable[[ConstraintViolation], None]] = field(default_factory=list)\\n   132│     # 路由成功回调\\n   133│     route_callbacks: List[Callable[[TaskType, Agent, Any], None]] = field(default_factory=list)\\n   134│ \\n   135│     def set_emergency_password(self, password: str) -> None:\\n   136│         \\\"\\\"\\\"设置紧急模式密码（存储简单哈希）\\\"\\\"\\\"\\n   137│         import hashlib\\n   138│         self._emergency_password_hash = hashlib.sha256(password.encode()).hexdigest()[:16]\\n   139│ \\n   140│     def verify_emergency_password(self, password: str) -> bool:\\n   141│         \\\"\\\"\\\"验证紧急模式密码\\\"\\\"\\\"\\n   142│         if self._emergency_password_hash is None:\\n   143│             return False\\n   144│         import hashlib\\n   145│         return hashlib.sha256(password.encode()).hexdigest()[:16] == self._emergency_password_hash\\n   146│ \\n   147│ \\n   148│ # ───────────────────────────────────────────────────────────────\\n   149│ # 系统约束层核心类\\n   150│ # ───────────────────────────────────────────────────────────────\\n   151│ \\n   152│ class SystemConstraint:\\n   153│     \\\"\\\"\\\"系统级约束层\\n   154│ \\n   155│     负责：\\n   156│     1. 自动路由任务到正确的 Agent\\n   157│     2. 拦截 Hermes 的违规操作\\n   158│     3. 记录和报告约束违规\\n   159│     4. 支持紧急模式覆盖（需密码）\\n   160│ \\n   161│     使用示例：\\n   162│         constraint = SystemConstraint()\\n   163│         # 自动路由编码任务到 Claude\\n   164│         result = constraint.route_task(\\\"code\\\", {\\\"feature_id\\\": \\\"F001\\\"})\\n   165│         # 拦截 Hermes 尝试编码\\n   166│         constraint.hermes_only_orchestration(\\\"code\\\")  # 抛出 ConstraintViolation\\n   167│     \\\"\\\"\\\"\\n   168│ \\n   169│     def __init__(self, config: Optional[ConstraintConfig] = None) -> None:\\n   170│         self.config = config or ConstraintConfig()\\n   171│         self._violation_count: int = 0\\n   172│         self._route_count: int = 0\\n   173│         self._emergency_active: bool = False\\n   174│         self._emergency_until: float = 0.0\\n   175│ \\n   176│     # ───────────────────────────────────────────────────────────\\n   177│     # 属性\\n   178│     # ───────────────────────────────────────────────────────────\\n   179│ \\n   180│     @property\\n   181│     def violation_count(self) -> int:\\n   182│         \\\"\\\"\\\"累计违规次数\\\"\\\"\\\"\\n   183│         return self._violation_count\\n   184│ \\n   185│     @property\\n   186│     def route_count(self) -> int:\\n   187│         \\\"\\\"\\\"累计路由次数\\\"\\\"\\\"\\n   188│         return self._route_count\\n   189│ \\n   190│     @property\\n   191│     def is_emergency_active(self) -> bool:\\n   192│         \\\"\\\"\\\"紧急模式是否激活\\\"\\\"\\\"\\n   193│         import time\\n   194│         if self._emergency_active and time.time() > self._emergency_until:\\n   195│             self._emergency_active = False\\n   196│         return self._emergency_active\\n   197│ \\n   198│     # ───────────────────────────────────────────────────────────\\n   199│     # 核心路由方法\\n   200│     # ───────────────────────────────────────────────────────────\\n\\n[TRUNCATED] Showing lines 1-200 of 578. To continue, call read_file with path=\\\"C:\\\\tmp\\\\multi-agent-pipeline\\\\src\\\\system_constraint.py\\\" start_line=201 max_lines=200\\n</file>\"",
