\\\"\\\"\\\"\\n    51│     name: str\\n    52│     priority: LayerPriority\\n    53│     content: str\\n    54│     compressible: bool = True\\n    55│     # 元数据：用于 Agentic Search 按需加载\\n    56│     tags: List[str] = field(default_factory=list)\\n    57│     source: str = \\\"\\\"  # 来源标识（如文件路径）\\n    58│ \\n    59│     def estimated_tokens(self) -> int:\\n    60│         \\\"\\\"\\\"估算该层占用的 token 数\\\"\\\"\\\"\\n    61│         return max(1, int(len(self.content) * TOKEN_ESTIMATE_FACTOR))\\n    62│ \\n    63│ \\n    64│ @dataclass\\n    65│ class ReinforcementPrompt:\\n    66│     \\\"\\\"\\\"Reinforcement 强化提示结构\\\"\\\"\\\"\\n    67│     current_task: str = \\\"\\\"\\n    68│     acceptance_criteria: str = \\\"\\\"\\n    69│     completed_steps: str = \\\"\\\"\\n    70│     current_step: str = \\\"\\\"\\n    71│     tool_result: str = \\\"\\\"\\n    72│     reminder: str = \\\"\\\"\\n    73│ \\n    74│     def build(self) -> str:\\n    75│         \\\"\\\"\\\"构建 Reinforcement 提示文本\\\"\\\"\\\"\\n    76│         parts = []\\n    77│         if self.current_task:\\n    78│             parts.append(f\\\"[当前任务] {self.current_task}\\\")\\n    79│         if self.acceptance_criteria:\\n    80│             parts.append(f\\\"[验收标准] {self.acceptance_criteria}\\\")\\n    81│         if self.completed_steps:\\n    82│             parts.append(f\\\"[已完成] {self.completed_steps}\\\")\\n    83│         if self.current_step:\\n    84│             parts.append(f\\\"[当前步骤] {self.current_step}\\\")\\n    85│         if self.tool_result:\\n    86│             parts.append(f\\\"[工具结果] {self.tool_result}\\\")\\n    87│         if self.reminder:\\n    88│             parts.append(f\\\"[提醒] {self.reminder}\\\")\\n    89│         return \\\"\\\\n\\\".join(parts)\\n    90│ \\n    91│ \\n    92│ @dataclass\\n    93│ class SearchResult:\\n    94│     \\\"\\\"\\\"Agentic Search 搜索结果\\\"\\\"\\\"\\n    95│     content: str\\n    96│     source: str\\n    97│     relevance_score: float = 0.0\\n  