-> None:\\n   241│         self.usd_budget = USDBudget(limit_usd=self.project_usd_limit)\\n   242│ \\n   243│     # ── Feature management ──────────────────────────────────\\n   244│ \\n   245│     def add_feature(\\n   246│         self,\\n   247│         feature_id: str,\\n   248│         token_limit: Optional[int] = None,\\n   249│     ) -> FeatureBudget:\\n   250│         \\\"\\\"\\\"Register a feature for budget tracking.\\n   251│ \\n   252│         Args:\\n   253│             feature_id: Unique feature identifier.\\n   254│             token_limit: Max tokens for this feature (defaults to default_feature_token_limit).\\n   255│ \\n   256│         Returns:\\n   257│             The created or existing FeatureBudget.\\n   258│         \\\"\\\"\\\"\\n   259│         if feature_id in self.features:\\n   260│             return self.features[feature_id]\\n   261│ \\n   262│         limit = token_limit if token_limit is not None else self.default_feature_token_limit\\n   263│         tb = TokenBudget(limit=limit)\\n   264│         fb = FeatureBudget(feature_id=feature_id, token_budget=tb)\\n   265│         self.features[feature_id] = fb\\n   266│         return fb\\n   267│ \\n   268│     def get_feature(self, feature_id: str) -> Optional[FeatureBudget]:\\n   269│         \\\"\\\"\\\"Get a feature's budget record.\\\"\\\"\\\"\\n   270│         return self.features.get(feature_id)\\n   271│ \\n   272│     def remove_feature(self, feature_id: str) -> None:\\n   273│         \\\"\\\"\\\"Remove a feature from tracking.\\\"\\\"\\\"\\n   274│         self.features.pop(feature_id, None)\\n   275│ \\n   276│     # ── Budget checks ───────────────────────────────────────\\n   277│ \\n   278│     def check_feature(self, feature_id: str) -> BudgetLevel:\\n   279│         \\\"\\\"\\\"Check a single feature's token budget status.\\\"\\\"\\\"\\n   280│         fb = self.features.get(feature_id)\\n   281│         if fb is None:\\n   282│             return BudgetLevel.UNLIMITED\\n   283│         return BudgetLevel(fb.token_budget.check())\\n   284│ \\n   285│     def check_project(self) -> BudgetLevel:\\n   286│         \\\"\\\"\\\"Check the project-level USD budget status.\\\"\\\"\\\"\\n   287│         return self.usd_budget.check()\\n   288│ \\n   289│     def check_all(self, feature_id: Optional[str] = None) -> Dict[str, BudgetLevel]:\\n   290│         \\\"\\\"\\\"Check both feature and project budgets.\\n   291│ \\n   292│         Returns dict with 'feature' and 'project' keys.\\n   293│         \\\"\\\"\\\"\\n   294│         return {\\n   295│             \\\"feature\\\": self.check_feature(feature_id) if feature_id else BudgetLevel.OK,\\n   296│             \\\"project\\\": self.check_project(),\\n   297│         }\\n   298│ \\n   299│     def can_proceed(\\n   300│         self,\\n   301│         feature_id: Optional[str] = None,\\n   302│         estimated_tokens: int = 0,\\n   303│         estimated_cost: float = 0.0,\\n   304│     ) -> Tuple[bool, BudgetLevel, str]:\\n   305│         \\\"\\\"\\\"Pre-flight check: can this operation proceed?\\n   306│ \\n   307│         Returns:\\n   308│             Tuple of (allowed, worst_level, reason).\\n   309│             allowed=False means HARD_CAP — operation must be rejected.\\n   310│             allowed=True with worst_level=WARNING/SOFT_CAP means proceed with caution.\\n   311│         \\\"\\\"\\\"\\n   312│         worst_level = BudgetLevel.OK\\n   313│         reasons: List[str] = []\\n   314│ \\n   315│         # Check feature token budget\\n   316│         if feature_id and feature_id in self.features:\\n   317│             fb = self.features[feature_id]\\n   318│             if estimated_tokens > 0:\\n   319│                 projected = fb.token_spent + estimated_tokens\\n   320│                 fb.token_budget.spent = projected\\n   321│                 flevel = BudgetLevel(fb.token_budget.check())\\n   322│                 fb.token_budget.spent = fb.token_spent  # restore\\n   323│             else:\\n   324│                 flevel = BudgetLevel(fb.token_budget.check())\\n   325│ \\n   326│             if flevel == BudgetLevel.HARD_CAP:\\n   327│                 return (\\n   328│                     False,\\n   329│                     BudgetLevel.HARD_CAP,\\n   330│                     f\\\"Feature '{feature_id}' token budget exceeded hard cap \\\"\\n   331│                     f\\\"({fb.token_spent}/{fb.token_budget.limit} tokens)\\\",\\n   332│                 )\\n   333│             if flevel.value > worst_level.value:\\n   334│                 worst_level = flevel\\n   335│             if flevel != BudgetLevel.OK and flevel != BudgetLevel.UNLIMITED:\\n   336│                 reasons.append(f\\\"Feature '{feature_id}' token: {flevel.value}\\\")\\n   337│ \\n   338│         # Check project USD budget\\n   339│         if estimated_cost > 0:\\n   340│             projected_usd = self._total_usd_spent + estimated_cost\\n   341│             temp_budget = USDBudget(\\n   342│                 limit_usd=self.usd_budget.limit_usd,\\n   343│                 spent_usd=projected_usd,\\n   344│             )\\n   345│             plevel = temp_budget.check()\\n   346│         else:\\n   347│             plevel = self.usd_budget.check()\\n   348│ \\n   349│         if plevel == BudgetLevel.HARD_CAP:\\n   350│             return (\\n   351│                 False,\\n   352│                 BudgetLevel.HARD_CAP,\\n   353│                 f\\\"Project USD budget exceeded hard cap \\\"\\n   354│                 f\\\"(${self._total_usd_spent:.2f}/${self.usd_budget.limit_usd:.2f})\\\",\\n   355│             )\\n   356│         if plevel.value > worst_level.value:\\n   357│             worst_level = plevel\\n   358│         if plevel != BudgetLevel.OK and plevel != BudgetLevel.UNLIMITED:\\n   359│             reasons.append(f\\\"Project USD: {plevel.value}\\\")\\n   360│ \\n   361│         reason = \\\"; \\\".join(reasons) if reasons else \\\"ok\\\"\\n  